INSERT INTO `product` (`ProductId`, `ProductName`, `ProductCategory`, `ProductPoints`, `ProductQuantity`, `ProductImage`, `ProductDescription`, `SupplierId`) VALUES
(49, 'Lancome Absolute Soft Cream ', 'COSMETIC', 7950, 10, , 'WHAT MAKES THE DIFFERENCE\r\nInspired by its exceptional vitality, our lab has turned to a phenomenon of nature: The Absolue Perpetual Rose™️, growing only in the Valensole plateau and blooming vividly almost all year round. Millions of rose molecular fractions are encapsulated in our legendary Patented* Absolue The Soft Cream. From thick to thin, its texture softens on the skin, leaving a moisturizing and brightening effect. Each day, skin is revitalized with millions of new skin cells.\r\n*Patented for France, Patent pending for other countries\r\n\r\nWHAT ELSE YOU NEED TO KNOW\r\nOur Absolue The Soft Cream has been redesigned in an eco-responsible approach to encourage responsible consumption. Make more sustainable consumption choices. Simply remove the capsule and install the recharge into your empty pack.', 28);
INSERT INTO `product` (`ProductId`, `ProductName`, `ProductCategory`, `ProductPoints`, `ProductQuantity`, `ProductImage`, `ProductDescription`, `SupplierId`) VALUES
(50, 'Advanced Genifique Sensitive Serum', 'COSMETIC', 4000, 3, , 'Lancôme’s unique Génifique expertise, inspired by microbiome science, is now encapsulated in our updated formula Advanced Génifique Sensitive, an active recovery, soothing facial serum. Proven to strengthen skins barrier, instantly soothe the feeling of stressed skin to leave skin feeling balanced and looking healthy.\r\n\r\nSeasonal changes, environmental aggressions, and the stress of modern life can make skin react with feelings of tightness and discomfort, and lead to premature signs of skin aging. With its unique formula enriched with 7 prebiotic and probiotic derived extracts, this intense recovery concentrate helps strengthen the skin barrier and protect against the effect of daily aggressors. Two active concentrates in one, separate until first use to maintain their freshness. The blue concentrate, enriched with antioxidant Ferulic acid and Vitamin E, is released into the serum base on first use to create an active recovery concentrate, helping soothe the feel of skin and keep it balanced. Helping to improve the signs of stressed skin: dullness, dryness.\r\n\r\nFor all skin types, even reactive and sensitive.', 28);
INSERT INTO `product` (`ProductId`, `ProductName`, `ProductCategory`, `ProductPoints`, `ProductQuantity`, `ProductImage`, `ProductDescription`, `SupplierId`) VALUES
(51, 'Round Lab Dokdo Lotion 200ml Soothe skin\'s', 'COSMETIC', 660, 150, , 'Round Wrap Dokdo Lotion is a product that hydrates and helps to calm skin. This lotion is especially suitable for people with sensitive skin, and provides gentle yet effective moisturization.\r\n\r\nRound Wrap Dokdo Lotion helps calm and moisturize the skin, which can contribute to healthy skin care. It is especially recommended for those with sensitive skin!', 27);
INSERT INTO `product` (`ProductId`, `ProductName`, `ProductCategory`, `ProductPoints`, `ProductQuantity`, `ProductImage`, `ProductDescription`, `SupplierId`) VALUES
(52, 'Round Lab 1025 Dokdo Sunscreen SPF 50+, PA++++', 'COSMETIC', 800, 999, , 'A powerful sunscreen, especially for the acne-prone & sensitive skin, \r\nthat blocks the harsh UV rays and cares for healthier skin. (Reef Safe, Clinically proven SPF 50+ PA++++)\r\n\r\nMoisturizing: Moisturizes and hydrates the skin.\r\nSunscreen: It protects your skin from UV rays and keeps you healthy.\r\nWhitening and wrinkle improvement: It helps with whitening of the skin and is also effective in improving wrinkles', 27);
INSERT INTO `product` (`ProductId`, `ProductName`, `ProductCategory`, `ProductPoints`, `ProductQuantity`, `ProductImage`, `ProductDescription`, `SupplierId`) VALUES
(53, 'All purpose hammer', 'TOOLS', 500, 1000, , 'All purpose hammer that has long longtivity.', 29);
